SELECT vtk_class_name, vtk_class_description 
FROM vtk_classes 
WHERE deprecated = 0;

SELECT AVG(r.rating_value) AS average_rating
FROM ratings r
WHERE r.vtk_class_id = 1;

SELECT AVG(rating_value) AS average_rating
FROM ratings
WHERE vtk_class_id = 1;

SELECT vtk_classes.vtk_class_name
FROM comments
JOIN vtk_classes ON comments.vtk_class_id = vtk_classes.vtk_class_id;

SELECT vtk_classes.vtk_class_name, categories.category_name
FROM vtk_classes
INNER JOIN categories ON vtk_classes.category_id = categories.category_id;

SELECT DISTINCT v.vtk_class_id, v.vtk_class_name, v.vtk_class_description, v.category_id, v.version, v.created_at, v.updated_at, v.deprecated
FROM vtk_classes v
JOIN usage_examples u ON v.vtk_class_id = u.vtk_class_id;

SELECT COUNT(vtk_class_id) AS Number_of_VTK_Classes
FROM vtk_classes
WHERE deprecated = 1;

SELECT users.user_id, users.user_name, users.email, revisions.revision_notes, revisions.revision_date
FROM users
INNER JOIN revisions ON users.user_id = revisions.user_id;

SELECT COUNT(*) AS total_comments
FROM comments
WHERE vtk_class_id = 0;

SELECT * 
FROM vtk_classes
ORDER BY vtk_class_name ASC;

SELECT vtk_class_name, version
FROM vtk_classes
ORDER BY created_at DESC;
